const body = $input.item.json.body || {};
const alert = $input.item.json.alert || {};
const chatId = body.chat_id || body.telegram_chat_id || '';
const runDate = body.run_date || '';

if (!chatId) {
  return [];
}

const dirEmoji = { up: '🟢', down: '🔴', neutral: '🟡' }[alert.direction] || '⚪';
const signalLabel = {
  quality: 'Quality',
  momentum: 'Momentum',
  news_catalyst: 'News Catalyst',
  risk_flag: 'Data Risk'
}[alert.signal_type] || alert.signal_type;

const urgency = (alert.urgency || alert.severity || '').toString().toUpperCase();
const action = alert.action_frame ? `\nAction: ${alert.action_frame}` : '';
const narrative = alert.narrative ? `\n${alert.narrative}` : '';

const message = `${dirEmoji} *${alert.ticker || ''}* — ${signalLabel}\nUrgency: ${urgency}\nRun: ${runDate}${action}${narrative}`;

return [{ json: { message, chat_id: chatId } }];
